    @Test func insertionContextUsesAccessibilityUTF16Offsets() async throws {
        let prefix = "Say 😄 so this"
        let fullText = "\(prefix) model"
        let selectedRange = CFRange(location: prefix.utf16.count, length: 0)

        let context = TranscriptionOutputFilter.insertionContext(
            fromFullText: fullText,
            selectedRange: selectedRange,
            selectedText: nil
        )

        #expect(context.precedingText == prefix)
        #expect(TranscriptionOutputFilter.applyInsertionPolish("Model.", context: context) == "model")
        #expect(TranscriptionOutputFilter.applyInsertionSpacing("model", context: context) == " model")
    }

    @Test func transcriptionFilterRespectsCleanupLevels() async throws {
        let oldRemoveFillerWords = UserDefaults.standard.object(forKey: "RemoveFillerWords")
        let oldCleanupLevel = UserDefaults.standard.object(forKey: TranscriptionCleanupLevel.userDefaultsKey)
        defer {
            if let oldRemoveFillerWords {
                UserDefaults.standard.set(oldRemoveFillerWords, forKey: "RemoveFillerWords")
            } else {
                UserDefaults.standard.removeObject(forKey: "RemoveFillerWords")
            }
            if let oldCleanupLevel {
                UserDefaults.standard.set(oldCleanupLevel, forKey: TranscriptionCleanupLevel.userDefaultsKey)
            } else {
                UserDefaults.standard.removeObject(forKey: TranscriptionCleanupLevel.userDefaultsKey)
            }
        }

        UserDefaults.standard.set(true, forKey: "RemoveFillerWords")

        TranscriptionCleanupLevel.setCurrent(.raw)
        #expect(TranscriptionOutputFilter.filter("hmm... Hello comma world. Hello comma world.") == "hmm... Hello comma world. Hello comma world.")
        #expect(TranscriptionOutputFilter.filter("This, um, works.") == "This, um, works.")
        #expect(TranscriptionOutputFilter.filter("I can apostrophe t go.") == "I can apostrophe t go.")
        #expect(TranscriptionOutputFilter.filter("Felix apostrophe s laptop.") == "Felix apostrophe s laptop.")
        #expect(TranscriptionOutputFilter.filter("Wrong phrase scratch that. Right phrase.") == "Wrong phrase scratch that. Right phrase.")
        #expect(TranscriptionOutputFilter.filter("Wrong phrase undo that. Right phrase.") == "Wrong phrase undo that. Right phrase.")
        #expect(TranscriptionOutputFilter.filter("Use model replace that with module.") == "Use model replace that with module.")

        TranscriptionCleanupLevel.setCurrent(.light)
        #expect(TranscriptionOutputFilter.filter("hmm... Hello comma world.") == "hmm... Hello, world.")
        #expect(TranscriptionOutputFilter.filter("This, um, works.") == "This, um, works.")
        #expect(TranscriptionOutputFilter.filter("I can apostrophe t go.") == "I can't go.")
        #expect(TranscriptionOutputFilter.filter("Felix apostrophe s laptop.") == "Felix's laptop.")
        #expect(TranscriptionOutputFilter.filter("Wrong phrase scratch that. Right phrase.") == "Wrong phrase scratch that. Right phrase.")
        #expect(TranscriptionOutputFilter.filter("Wrong phrase undo that. Right phrase.") == "Wrong phrase undo that. Right phrase.")
        #expect(TranscriptionOutputFilter.filter("Use model replace that with module.") == "Use model replace that with module.")
        #expect(TranscriptionOutputFilter.filter("Let's meet at two, wait no, three.") == "Let's meet at two, wait no, three.")
        #expect(TranscriptionOutputFilter.filter("I think I think this works.") == "I think I think this works.")
        #expect(TranscriptionOutputFilter.filter("I think this works, I think this works.") == "I think this works, I think this works.")

        TranscriptionCleanupLevel.setCurrent(.polished)
        #expect(TranscriptionOutputFilter.filter("hmm... Hello comma world.") == "Hello, world.")
        #expect(TranscriptionOutputFilter.filter("This, um, works.") == "This works.")
        #expect(TranscriptionOutputFilter.filter("hmm — I think this works.") == "I think this works.")
        #expect(TranscriptionOutputFilter.filter("eh... : this works.") == "this works.")
        #expect(TranscriptionOutputFilter.filter("— I think this works.") == "— I think this works.")
        #expect(TranscriptionOutputFilter.filter("- item one.") == "- item one")
        #expect(TranscriptionOutputFilter.filter("Let's meet at two, wait no, three.") == "Let's meet at three.")
        #expect(TranscriptionOutputFilter.filter("I think I think this works.") == "I think this works.")
        #expect(TranscriptionOutputFilter.filter("I, I think this works.") == "I think this works.")
        #expect(TranscriptionOutputFilter.filter("This this.") == "This.")
        #expect(TranscriptionOutputFilter.filter("No, no, this is wrong.") == "No, no, this is wrong.")
        #expect(TranscriptionOutputFilter.filter("I - I think this works.") == "I think this works.")
        #expect(TranscriptionOutputFilter.filter("This — this works.") == "This works.")
        #expect(TranscriptionOutputFilter.filter("x - x is zero.") == "x - x is zero.")
        #expect(TranscriptionOutputFilter.filter("No - no, this is wrong.") == "No - no, this is wrong.")
        #expect(TranscriptionOutputFilter.filter("I think this works, I think this works.") == "I think this works.")
        #expect(TranscriptionOutputFilter.filter("I think this works! I think this works.") == "I think this works.")
        #expect(TranscriptionOutputFilter.filter("I think this works. I think this works!") == "I think this works.")
        #expect(TranscriptionOutputFilter.filter("Hello world! Hello world.") == "Hello world.")
        #expect(TranscriptionOutputFilter.filter("No? No.") == "No? No.")
        #expect(TranscriptionOutputFilter.filter("So this. Model.") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this. Model") == "So this model")
        #expect(TranscriptionOutputFilter.filter("So this. The model") == "So this the model")
        #expect(TranscriptionOutputFilter.filter("So this. Model final word") == "So this model final word")
        #expect(TranscriptionOutputFilter.filter("So this. [Model.]") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this, [Model.]") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this - [Model.]") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this: [Model.]") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this. \"[Model.]\"") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this. ([Model.])") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this. <[Model.]>") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this. 【Model.】") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this. *Model.*") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("So this, \"[Model.]\"") == "So this model.")
        #expect(TranscriptionOutputFilter.filter("I think this is. [A final word.]") == "I think this is a final word.")
        #expect(TranscriptionOutputFilter.filter("I live in. [U.S.]") == "I live in U.S.")
        #expect(TranscriptionOutputFilter.filter("It is. What?") == "It is. What?")
        #expect(TranscriptionOutputFilter.filter("It is. [What?]") == "It is. [What?]")
        #expect(TranscriptionOutputFilter.filter("It works. Model") == "It works. Model")
        #expect(TranscriptionOutputFilter.applyInsertionPolish("It works. [Model.]", context: nil) == "It works. [Model.]")
        #expect(TranscriptionOutputFilter.applyInsertionPolish("It works, [Model.]", context: nil) == "It works, [Model.]")
        #expect(TranscriptionOutputFilter.applyInsertionPolish("It works. \"[Model.]\"", context: nil) == "It works. \"[Model.]\"")
    }

    @Test func transcriptionFilterAppliesBoundedBacktrackingCorrections() async throws {
        TranscriptionCleanupLevel.setCurrent(.polished)
        #expect(TranscriptionOutputFilter.filter("Let's meet at two, wait no, three.") == "Let's meet at three.")
        #expect(TranscriptionOutputFilter.filter("Let's meet at two, no wait, three.") == "Let's meet at three.")
